class TestCreateTables:
    async def test_creates_all_tables(self, db) -> None:
        cursor = await db.execute(
            "SELECT name FROM sqlite_master WHERE type='table' ORDER BY name"
        )
        tables = [row[0] for row in await cursor.fetchall()]
        assert "claude_sessions" in tables
        assert "claude_agents" in tables
        assert "claude_events" in tables
        assert "claude_costs" in tables

    async def test_idempotent(self, db) -> None:
        await schema.create_tables(db)
        await schema.create_tables(db)
        cursor = await db.execute(
            "SELECT count(*) FROM sqlite_master WHERE name='claude_sessions'"
        )
        row = await cursor.fetchone()
        assert row[0] == 1


class TestSessionCrud:
    async def test_upsert_inserts_new(self, db) -> None:
        await schema.upsert_session(
            db,
            session_id="s1",
            pid=1234,
            cwd="/tmp/proj",
            entrypoint="cli",
            started_at=1000,
            last_event="PreToolUse",
            last_tool="Bash",
            last_event_at=1.0,
        )
        row = await schema.get_session(db, session_id="s1")
        assert row is not None
        assert row["pid"] == 1234
        assert row["last_event"] == "PreToolUse"
        assert row["last_tool"] == "Bash"

    async def test_upsert_updates_existing(self, db) -> None:
        await schema.upsert_session(
            db,
            session_id="s1",
            pid=1234,
            cwd="/tmp/proj",
            last_event="PreToolUse",
            last_tool="Bash",
            last_event_at=1.0,
        )
        await schema.upsert_session(
            db,
            session_id="s1",
            last_event="Stop",
            last_tool=None,
            last_event_at=2.0,
        )
        row = await schema.get_session(db, session_id="s1")
        assert row["last_event"] == "Stop"
        assert row["last_tool"] == "Bash"  # COALESCE keeps old value
        assert row["pid"] == 1234

    async def test_end_session(self, db) -> None:
        await schema.upsert_session(db, session_id="s1", pid=1234, cwd="/tmp")
        await schema.end_session(db, session_id="s1", ended_at=99.0)
        row = await schema.get_session(db, session_id="s1")
        assert row["ended_at"] == 99.0

