    async def test_get_all_sessions_active_filter(self, db) -> None:
        await schema.upsert_session(db, session_id="alive", pid=1, cwd="/a")
        await schema.upsert_session(db, session_id="dead", pid=2, cwd="/b")
        await schema.update_session_pid_alive(db, session_id="dead", pid_alive=False)

        active = await schema.get_all_sessions(db, active=True)
        assert len(active) == 1
        assert active[0]["session_id"] == "alive"

        inactive = await schema.get_all_sessions(db, active=False)
        assert len(inactive) == 1
        assert inactive[0]["session_id"] == "dead"

